%[text] #### Experiment 1
load("lab3_exp1_data.mat")

% Plot with currents as a function of base voltage
figure() %[output:4ef028c7]
yscale("log") %[output:4ef028c7]
hold on; %[output:4ef028c7]
semilogy(Vb, Ib, '.', DisplayName='Measured Base Current') %[output:4ef028c7]
yscale("log") %[output:4ef028c7]
semilogy(Vb, Iout, '.', DisplayName='Measured Collector Current') %[output:4ef028c7]
xlabel('Base Voltage (V)') %[output:4ef028c7]
ylabel('Current (A)') %[output:4ef028c7]
title('Bipolar Transistor Current Characteristics') %[output:4ef028c7]

vals_range = find(Vb > 0.5);
plot_range = linspace(0.3,0.7, 101);
[~, ~, m, b, ~] = linefit(Vb(vals_range), log(Ib(vals_range)), 1e-4);
plot(plot_range, exp(m .* plot_range + b), DisplayName=['Fit: y = e^{', num2str(m), 'x} ', char(8487), ' + e^{', num2str(b), '} A']) %[output:4ef028c7]

vals_range = find(Vb > 0.37);
plot_range = linspace(0.3,0.7, 101);
[~, ~, m, b, ~] = linefit(Vb(vals_range), log(Iout(vals_range)), 1e-4);
plot(plot_range, exp(m .* plot_range + b), DisplayName=['Fit: y = e^{', num2str(m), 'x} ', char(8487), ' + e^{', num2str(b), '} A']) %[output:4ef028c7]

legend(Location='southoutside') %[output:4ef028c7]

% Current Gain Plot
current_gain = Iout ./ Ib;

figure() %[output:59738c86]
semilogx(Ib, current_gain, '.', DisplayName='Measured') %[output:59738c86]
hold on; %[output:59738c86]
vals_range = find(Ib > 1e-10);
plot_range = logspace(-10, -5, 101);
% fit_vals = fit(log(Ib(vals_range))', log(current_gain(vals_range))', "exp(a * x + b)");
% plot(plot_range, exp(fit_vals(1) .* plot_range + fit_vals(2)), DisplayName='Theoretical Fit')

xlabel('Base Current (A)') %[output:59738c86]
ylabel('Current Gain, \beta (Unitless)') %[output:59738c86]
title('Bipolar Transistor Current Gain Characteristics') %[output:59738c86]
% legend(Location='southoutside')
axis([1e-10, 1e-4, 0, 300]) %[output:105e7b65] %[output:59738c86]

% r_b vs I_b
incremental_resistance = diff(Vb) ./ diff(Ib);

figure() %[output:011edaa5]
loglog(Ib(1:end-1), incremental_resistance, '.', DisplayName='Measured') %[output:011edaa5]
hold on; %[output:011edaa5]
plot(logspace(-10, -5, 101), 0.025 ./ logspace(-10, -5, 101), DisplayName='Theoretical Fit') %[output:011edaa5]

xlabel('Base Current (A)') %[output:011edaa5]
ylabel('Incremental Resistance, r_{b} (\Omega)') %[output:011edaa5]
title('Bipolar Transistor Incremental Resistance Characteristics') %[output:011edaa5]
legend(Location='southoutside') %[output:011edaa5]

% g_m vs I_c
incremental_transconductance_gain = diff(Iout) ./ diff(Vb);

figure() %[output:63f26b78]
loglog(Iout(1:end-1), incremental_transconductance_gain, '.', DisplayName='Measured') %[output:63f26b78]
hold on; %[output:63f26b78]
plot(logspace(-10, -2, 101), logspace(-10, -2, 101) ./ 0.025, DisplayName='Theoretical Fit') %[output:63f26b78]

xlabel('Collector Current (A)') %[output:63f26b78]
ylabel(['Incremental Transconductance Gain, g_{m} (', char(8487), ')']) %[output:63f26b78]
title('Bipolar Transistor Incremental Transconductance Characteristics') %[output:63f26b78]
legend(Location='southoutside') %[output:63f26b78]
%[text] #### Experiment 4
load("lab3_exp3_data.mat")
load("lab3_exp4_data.mat")

% Voltage Transfer Characteristic Plot + Experiment 3 Plot
figure() %[output:98b27cd7]
hold on; %[output:98b27cd7]
plot(Vin10k_e4, Vout10k_e4, '.', DisplayName='mR = 10 k\Omega; R = 1 k\Omega') %[output:98b27cd7]
plot(Vin5k_e4, Vout5k_e4, '.', DisplayName='mR = 5 k\Omega; R = 1 k\Omega') %[output:98b27cd7]
plot(Vin2k_e4, Vout2k_e4, '.', DisplayName='mR = 2 k\Omega; R = 1 k\Omega') %[output:98b27cd7]
plot(Vin_e3, Vout_e3, '.', DisplayName='mR = 0 \Omega; R = 1 k\Omega (Common Collector Amplifier)') %[output:98b27cd7]

fit_vals = polyfit(Vin_e3(find(Vout_e3 > 0.75)), Vout_e3(find(Vout_e3 > 0.75)), 1);
plot(linspace(0, 5, 101), fit_vals(1) .* linspace(0, 5, 101) + fit_vals(2), DisplayName=['Common Collector Amplifier Behavior Fit: y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:98b27cd7]

vals_range = find(Vin10k_e4 > 0.5 & Vin10k_e4 < 1.15);
plot_range = linspace(0.5, 1.25, 101);
fit_vals = polyfit(Vin10k_e4(vals_range), Vout10k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 10 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:98b27cd7]

vals_range = find(Vin5k_e4 > 0.5 & Vin5k_e4 < 1.5);
plot_range = linspace(0.5, 1.75, 101);
fit_vals = polyfit(Vin5k_e4(vals_range), Vout5k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 5 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:98b27cd7]

vals_range = find(Vin2k_e4 > 0.5 & Vin2k_e4 < 2.2);
plot_range = linspace(0.5, 3, 101);
fit_vals = polyfit(Vin2k_e4(vals_range), Vout2k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 2 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:98b27cd7]

title('Common-Emitter Amplifier Voltage Transfer Characteristics') %[output:98b27cd7]
xlabel('Input Voltage (V)') %[output:98b27cd7]
ylabel('Output Voltage (V)') %[output:98b27cd7]
legend(Location="southoutside") %[output:98b27cd7] %[output:0d0f93c6] %[output:8541f7d4] %[output:02879dc4] %[output:91d8a1c1] %[output:7885577d] %[output:057e0574]

